import{c as e,Q as r,j as o,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Chronos: Temporal-Aware Conversational Agents with Structured Event Retrieval for Long-Term Memory","description":"","frontmatter":{"title":"Chronos: Temporal-Aware Conversational Agents with Structured Event Retrieval for Long-Term Memory","arxiv_id":2603.16862,"authors":"Sahil Sen, Elias Lumer, Anmol Gulati, Vamse Kumar Subbiah","fetched":"2026-05-26T00:00:00.000Z","published":"2026-03-17T00:00:00.000Z","source":"https://arxiv.org/abs/2603.16862","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-03-17-chronos-temporal-aware-conversational-agents-2603-16862.md","filePath":"research/papers/2026-03-17-chronos-temporal-aware-conversational-agents-2603-16862.md","lastUpdated":1779901665000}'),a={name:"research/papers/2026-03-17-chronos-temporal-aware-conversational-agents-2603-16862.md"};function s(i,t,d,l,g,c){return r(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="chronos-temporal-aware-conversational-agents-with-structured-event-retrieval-for-long-term-memory" tabindex="-1">Chronos: Temporal-Aware Conversational Agents with Structured Event Retrieval for Long-Term Memory <a class="header-anchor" href="#chronos-temporal-aware-conversational-agents-with-structured-event-retrieval-for-long-term-memory" aria-label="Permalink to &quot;Chronos: Temporal-Aware Conversational Agents with Structured Event Retrieval for Long-Term Memory&quot;">​</a></h1><p><strong>Authors</strong>: Sahil Sen, Elias Lumer, Anmol Gulati, Vamse Kumar Subbiah (Commercial Technology and Innovation Office, PricewaterhouseCoopers U.S.) <strong>Published</strong>: March 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2603.16862" target="_blank" rel="noreferrer">https://arxiv.org/abs/2603.16862</a><strong>arXiv ID</strong>: 2603.16862 <strong>Categories</strong>: cs.CL</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Recent advances in Large Language Models (LLMs) have enabled conversational AI agents to engage in extended multi-turn interactions spanning weeks or months. However, existing memory systems struggle to reason over temporally grounded facts and preferences that evolve across months of interaction and lack effective retrieval strategies for multi-hop, time-sensitive queries over long dialogue histories. We introduce Chronos, a novel temporal-aware memory framework that decomposes raw dialogue into subject-verb-object event tuples with resolved datetime ranges and entity aliases, indexing them in a structured event calendar alongside a turn calendar that preserves full conversational context. At query time, Chronos applies dynamic prompting to generate tailored retrieval guidance for each question, directing the agent on what to retrieve, how to filter across time ranges, and how to approach multi-hop reasoning through an iterative tool-calling loop over both calendars. We evaluate Chronos with 8 LLMs, both open-source and closed-source, on the LongMemEvalS benchmark comprising 500 questions spanning six categories of dialogue history tasks. Chronos Low achieves 92.60% and Chronos High scores 95.60% accuracy, setting a new state of the art with an improvement of 7.67% over the best prior system. Ablation results reveal the events calendar accounts for a 58.9% gain on the baseline while all other components yield improvements between 15.5% and 22.3%. Notably, Chronos Low alone surpasses prior approaches evaluated under their strongest model configurations.</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>Chronos achieves state-of-the-art conversational long-term memory by combining selective temporal event extraction (SVO tuples with ISO 8601 datetime ranges) with raw turn preservation and dynamic per-query retrieval guidance — avoiding both the overhead of comprehensive knowledge graphs and the temporal blindness of pure turn-level retrieval. The key insight is that structuring only temporally-grounded events while retaining full dialogue context is sufficient for accurate update tracking, preference recall, and relative date reasoning across months of interaction.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>The rapid progress of LLMs has enabled conversational AI agents to maintain contextual awareness across extended multi-turn interactions, supporting personalized assistance over weeks or months of conversation history. With breakthroughs in RAG for conversational memory, LLM agents can efficiently access historical information without exhausting context window limits.</p><p>Despite these advancements, conversational memory systems have struggled to find the right balance between structured knowledge building and retrieval simplicity:</p><ul><li><strong>Knowledge graph systems</strong> extract all facts and relationships at ingestion time, building elaborate structures with entity resolution, fact validation, and temporal metadata — but create large knowledge bases even when queries require only a subset of information.</li><li><strong>Turn-level retrieval approaches</strong> avoid this overhead through direct dense-sparse hybrid search, but lack structured temporal representations needed for time-sensitive queries involving date calculations or cross-session event aggregation.</li><li><strong>Background reasoning pipelines</strong> generate derived facts, timelines, and behavioral patterns through offline &quot;dreaming&quot; or observational analysis, but these query-independent deductions introduce context entropy when precomputed knowledge proves irrelevant to specific questions.</li></ul><p>The core challenge: comprehensive memory building introduces overhead and context entropy through over-structuring, while pure turn-level retrieval lacks temporal grounding. No existing approach achieves query-conditioned selective extraction — structuring only the temporal information relevant to answering specific questions while preserving conversational context for semantic understanding.</p><p>Chronos addresses this by performing targeted event extraction focused on temporally-grounded state transitions and timestamped occurrences, indexed alongside raw conversation turns. To the authors&#39; knowledge, Chronos is the first architecture that combines the simplicity of turn-level retrieval with selective temporal event extraction.</p><hr><h2 id="_2-related-work" tabindex="-1">2. Related Work <a class="header-anchor" href="#_2-related-work" aria-label="Permalink to &quot;2. Related Work&quot;">​</a></h2><h3 id="_2-1-long-term-conversational-memory" tabindex="-1">2.1 Long-Term Conversational Memory <a class="header-anchor" href="#_2-1-long-term-conversational-memory" aria-label="Permalink to &quot;2.1 Long-Term Conversational Memory&quot;">​</a></h3><p>Modern LLM context windows largely address short-term (within-session) memory. Long-term (across-session) memory presents a harder challenge: retaining and retrieving information from conversations that occurred days or months earlier.</p><p>Two primary benchmarks evaluate long-term memory capabilities:</p><ul><li><strong>LongMemEvalS</strong>: 500 questions across six categories, including knowledge-update tracking, multi-session aggregation, and temporal reasoning.</li><li><strong>LoCoMo</strong>: Memory over naturalistic human conversations spanning up to 35 sessions, measuring single-hop, multi-hop, temporal, and adversarial QA.</li></ul><p>Neither benchmark isolates the role of temporal structuring in long-term memory.</p><h3 id="_2-2-knowledge-accumulation-and-representations" tabindex="-1">2.2 Knowledge Accumulation and Representations <a class="header-anchor" href="#_2-2-knowledge-accumulation-and-representations" aria-label="Permalink to &quot;2.2 Knowledge Accumulation and Representations&quot;">​</a></h3><p>Representations fall along a spectrum from structured to unstructured:</p><ul><li><strong>Structured end</strong>: Knowledge graphs encode entities and relationships as typed edges. Graph-based systems allow logical retrieval. More complex systems integrate three or more different types of nodes.</li><li><strong>Unstructured end</strong>: Systems preserve raw conversational text or generate natural language summaries. Some deploy specialized agents that monitor conversations and produce timestamped annotations. Others organize memory into hierarchical tiers.</li><li><strong>Hybrid approaches</strong>: Maintain both raw dialogue and extracted atomic facts as parallel corpora.</li></ul><p>A key tension: knowledge accumulation typically proceeds at ingestion time, independent of any future query. No existing scheme targets only temporally grounded events for structured indexing while retaining raw dialogue for general semantic queries.</p><h3 id="_2-3-retrieval-augmented-architectures" tabindex="-1">2.3 Retrieval-Augmented Architectures <a class="header-anchor" href="#_2-3-retrieval-augmented-architectures" aria-label="Permalink to &quot;2.3 Retrieval-Augmented Architectures&quot;">​</a></h3><ul><li><strong>Sparse retrieval</strong> (BM25): Excels at exact lexical matching, computationally efficient, but misses semantic variations.</li><li><strong>Dense retrieval</strong>: Captures semantic similarity but struggles with precise term matching and rare entities.</li><li><strong>Hybrid approaches</strong> fusing both modalities (reciprocal rank fusion or learned reranking) have emerged as the dominant paradigm in RAG systems.</li></ul><p>Pre-retrieval query processing techniques well-established in document retrieval — query rewriting, hypothetical document embeddings (HyDE), query decomposition — have not been applied to conversational long-term memory, where questions span categories demanding fundamentally different retrieval strategies.</p><p><strong>Agentic RAG</strong> transforms retrieval from single-shot to multi-step reasoning, but existing systems lack query-conditioned adaptation of the retrieval strategy itself.</p><h3 id="_2-4-summarization-and-fact-extraction" tabindex="-1">2.4 Summarization and Fact Extraction <a class="header-anchor" href="#_2-4-summarization-and-fact-extraction" aria-label="Permalink to &quot;2.4 Summarization and Fact Extraction&quot;">​</a></h3><ul><li><strong>Summarization</strong>: Recursive summarization, EDU extraction rewriting sessions into event-like statements.</li><li><strong>Fact extraction</strong>: Atomic knowledge units (entity-relation triples, timestamped observations). Most systems extract at ingestion time; query-conditioned variants additionally extract from retrieved turns at inference time.</li></ul><p>No existing system selectively structures only temporal events while preserving raw dialogue for semantic retrieval.</p><hr><h2 id="_3-the-chronos-architecture" tabindex="-1">3. The Chronos Architecture <a class="header-anchor" href="#_3-the-chronos-architecture" aria-label="Permalink to &quot;3. The Chronos Architecture&quot;">​</a></h2><p>Chronos maintains two complementary calendars:</p><ol><li><strong>Event calendar</strong>: Extracted temporal events with structured datetime ranges.</li><li><strong>Turn calendar</strong>: Raw conversational exchanges.</li></ol><p>Four main components:</p><h3 id="_3-1-event-extraction" tabindex="-1">3.1 Event Extraction <a class="header-anchor" href="#_3-1-event-extraction" aria-label="Permalink to &quot;3.1 Event Extraction&quot;">​</a></h3><p>The pipeline identifies temporally-grounded occurrences using LLM-powered extraction. Given a conversation turn with timestamp <code>t_conv</code>, the extractor identifies events with all of <code>⟨subject, verb, object⟩</code>.</p><p><strong>Multi-resolution temporal normalization</strong> converts natural language time references into precise ISO 8601 datetime ranges. Each event receives both <code>start_datetime</code> and <code>end_datetime</code> capturing the full temporal span. For ambiguous expressions like &quot;recently&quot; or &quot;last month,&quot; the system computes appropriate temporal windows centered on or relative to <code>t_conv</code> with appropriate granularity.</p><p><strong>Alias generation</strong>: The system generates 2-4 lexical aliases per event using completely different vocabulary to improve text search recall. For example, &quot;bought Fitbit&quot; generates aliases like &quot;picked up a fitness tracker,&quot; &quot;got a step counter,&quot; and &quot;purchased a wearable.&quot;</p><p><strong>Batch processing</strong>: Turns are processed in batches of maximum 25 turns, with 5-turn overlap between chunks.</p><p>Events are embedded using <code>text-embedding-3-large</code> and uploaded to the event calendar index; raw turns are embedded and uploaded to the turn calendar index.</p><h3 id="_3-2-dynamic-prompting" tabindex="-1">3.2 Dynamic Prompting <a class="header-anchor" href="#_3-2-dynamic-prompting" aria-label="Permalink to &quot;3.2 Dynamic Prompting&quot;">​</a></h3><p>Chronos introduces dynamic prompting for long-term memory, extending query rewriting from document retrieval to conversational memory. Rather than reformulating the search query itself, dynamic prompting analyzes each question to generate retrieval guidance tailored to the agent&#39;s reasoning process.</p><p>Given user query <code>q</code>, the system generates a custom instruction preamble directing the agent&#39;s attention to relevant information dimensions and retrieval strategies. A template generator (using Gemini 3 Flash) extracts question targets (entities, attributes, temporal constraints, operations) and outputs 1-5 concrete bullets describing what information to retrieve.</p><p>Example: Given &quot;What camera lens did I buy most recently?&quot;, the generator outputs: &quot;Pay close attention to the following information (current and past): Details about camera lens purchases, specifically the most recent purchase and the lens type/model.&quot;</p><p>Static prompts cannot anticipate the diversity of long-term memory queries: temporal filtering (&quot;What did I do last March?&quot;), preference recall (&quot;What kind of coffee do I like?&quot;), cross-session aggregation (&quot;How many times did I exercise?&quot;).</p><h3 id="_3-3-initial-retrieval" tabindex="-1">3.3 Initial Retrieval <a class="header-anchor" href="#_3-3-initial-retrieval" aria-label="Permalink to &quot;3.3 Initial Retrieval&quot;">​</a></h3><p>Three-stage pipeline:</p><ol><li><strong>Dense vector search</strong>: Query the turn calendar for top-100 conversation exchanges based on cosine similarity between <code>v_q</code> and <code>v_t</code>.</li><li><strong>Cross-encoder reranking</strong>: Cohere Rerank v3 rescores the 100 candidates; top-15 are selected.</li><li><strong>Context expansion</strong>: Each of the 15 selected turns is expanded with one turn before and one turn after from the same session.</li></ol><p>Retrieved turns are formatted into hierarchical natural language context blocks organized by conversation date (e.g., &quot;Session 1 (2024-02-15)&quot;) to make temporal relationships explicit.</p><h3 id="_3-4-chronos-agent" tabindex="-1">3.4 Chronos Agent <a class="header-anchor" href="#_3-4-chronos-agent" aria-label="Permalink to &quot;3.4 Chronos Agent&quot;">​</a></h3><p>An LLM agent with native tool-calling capabilities for iterative memory retrieval. Tools:</p><ul><li><code>search_turns</code>, <code>search_events</code>: Vector search for semantic retrieval.</li><li><code>grep_turns</code>, <code>grep_events</code>: Exact keyword matching for specific entities or exact phrases.</li></ul><p>The agent follows a <strong>ReAct reasoning pattern</strong>, alternating between thought generation, tool calling, and observation processing. Tool calls execute asynchronously with automatic retry logic. The agent can select top-k to retrieve; reranking from k=100 is applied using the original question (not the agent&#39;s query).</p><h3 id="_3-5-benchmark-notes" tabindex="-1">3.5 Benchmark Notes <a class="header-anchor" href="#_3-5-benchmark-notes" aria-label="Permalink to &quot;3.5 Benchmark Notes&quot;">​</a></h3><p>Evaluation uses LongMemEvalS&#39;s LLM judge. Manual inspection reveals benchmark limitations: some ground truth answers are inconsistent with the conversation history, and LLM-as-judge variability affects scoring on open-ended preference questions.</p><hr><h2 id="_4-experiments" tabindex="-1">4. Experiments <a class="header-anchor" href="#_4-experiments" aria-label="Permalink to &quot;4. Experiments&quot;">​</a></h2><p>Evaluation against state-of-the-art systems: EmergenceMem Internal, Honcho, Mastra, and Zep.</p><p>Two configurations:</p><ul><li><strong>Chronos Low</strong>: GPT-4o as generation model (matches all compared systems).</li><li><strong>Chronos High</strong>: Claude Opus 4.6 (higher capability tier).</li></ul><p>All runs use <code>text-embedding-3-large</code> with temperature = 0.</p><h3 id="_4-2-results" tabindex="-1">4.2 Results <a class="header-anchor" href="#_4-2-results" aria-label="Permalink to &quot;4.2 Results&quot;">​</a></h3><p><strong>Table 1: Chronos Low vs. baselines on LongMemEvalS (500 questions)</strong></p><table tabindex="0"><thead><tr><th>Method</th><th>Overall</th><th>KU</th><th>MS</th><th>SSA</th><th>SSP</th><th>SSU</th><th>TR</th></tr></thead><tbody><tr><td><strong>Chronos Low (Ours)</strong></td><td><strong>92.60</strong></td><td><strong>96.15</strong></td><td><strong>91.73</strong></td><td><strong>100.00</strong></td><td>80.00</td><td><strong>94.29</strong></td><td><strong>90.23</strong></td></tr><tr><td>Honcho†</td><td>90.40</td><td>94.87</td><td>84.96</td><td>96.43</td><td><strong>90.00</strong></td><td><strong>94.29</strong></td><td>88.72</td></tr><tr><td>EmergenceMem Internal</td><td>86.00</td><td>83.33</td><td>81.20</td><td><strong>100.00</strong></td><td>60.00</td><td><strong>98.57</strong></td><td>85.71</td></tr><tr><td>Mastra</td><td>84.80</td><td>85.90</td><td>79.70</td><td>82.14</td><td>73.33</td><td><strong>98.57</strong></td><td>85.71</td></tr><tr><td>Supermemory</td><td>81.60</td><td>88.50</td><td>71.40</td><td>96.40</td><td>70.00</td><td>97.10</td><td>76.70</td></tr><tr><td>Hindsight‡</td><td>83.60</td><td>84.60</td><td>79.70</td><td>94.60</td><td>66.70</td><td>95.70</td><td>79.70</td></tr><tr><td>Zep</td><td>71.20</td><td>83.30</td><td>57.90</td><td>80.40</td><td>56.70</td><td>92.90</td><td>62.40</td></tr><tr><td>Full-context</td><td>60.20</td><td>78.20</td><td>44.30</td><td>94.60</td><td>20.00</td><td>81.40</td><td>45.10</td></tr></tbody></table><p>† Honcho evaluated on Claude Haiku 4.5, not GPT-4o.<br> ‡ Hindsight evaluated with OSS-20B actor and OSS-120B judge.</p><p><strong>Table 2: Advanced LLM configurations on LongMemEvalS</strong></p><table tabindex="0"><thead><tr><th>Method</th><th>Overall</th><th>KU</th><th>MS</th><th>SSA</th><th>SSP</th><th>SSU</th><th>TR</th></tr></thead><tbody><tr><td><strong>Chronos High (Ours)</strong></td><td><strong>95.60</strong></td><td><strong>100.00</strong></td><td>88.72</td><td><strong>100.00</strong></td><td><strong>100.00</strong></td><td><strong>98.57</strong></td><td><strong>95.50</strong></td></tr><tr><td>Mastra</td><td>92.80</td><td>94.90</td><td><strong>87.20</strong></td><td>96.40</td><td>90.00</td><td>97.10</td><td>94.00</td></tr><tr><td>Honcho†</td><td>92.60</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>Hindsight‡</td><td>91.40</td><td>94.90</td><td>87.20</td><td>96.40</td><td>80.00</td><td>97.10</td><td>91.00</td></tr><tr><td>Supermemory</td><td>85.20</td><td>89.70</td><td>76.70</td><td>98.20</td><td>70.00</td><td>98.60</td><td>82.00</td></tr></tbody></table><p>Categories: KU = Knowledge Update, MS = Multi-Session Aggregation, SSA = Single-Session Assistant, SSP = Single-Session Preference, SSU = Single-Session User, TR = Temporal Reasoning.</p><h3 id="_4-3-discussion" tabindex="-1">4.3 Discussion <a class="header-anchor" href="#_4-3-discussion" aria-label="Permalink to &quot;4.3 Discussion&quot;">​</a></h3><ul><li><strong>Multi-session aggregation</strong> (&quot;How many times did I exercise in May?&quot;): Calendar-structured event index enables efficient temporal filtering, reducing retrieval entropy to time-based events only.</li><li><strong>Temporal reasoning</strong> (&quot;What did I do the week after my vacation?&quot;): Multi-resolution temporal normalization converts relative expressions into precise date ranges, shifting reasoning from string interpretation to structured filtering.</li><li><strong>Knowledge-update tracking</strong> (&quot;Where do I currently work?&quot;): Event extraction identifies each workplace mention as a separate timestamped event; agent retrieves all and selects most recent by datetime ordering.</li><li><strong>Single-session preference</strong> (SSP: 80%): Only category where Chronos Low trails Honcho (90%). Honcho&#39;s advantage reflects use of Claude Haiku 4.5, not an architectural advantage.</li></ul><p>Error analysis (Figure 3): Moving from Chronos Low to Chronos High halves counting/arithmetic errors. Retrieval failures remain the most common error category for both models, showing LLMs still fail to retrieve over large amounts of data even with specific guidance. No improvement on fabrication errors (frequent on abstention questions).</p><h3 id="_4-4-ablation-studies" tabindex="-1">4.4 Ablation Studies <a class="header-anchor" href="#_4-4-ablation-studies" aria-label="Permalink to &quot;4.4 Ablation Studies&quot;">​</a></h3><p>Ablations on a stratified 116-question subset (Table 3):</p><p><strong>Chronos Low ablations:</strong></p><table tabindex="0"><thead><tr><th>Ablation</th><th>Overall</th><th>KU</th><th>MS</th><th>SSA</th><th>SSP</th><th>SSU</th><th>TR</th></tr></thead><tbody><tr><td><strong>Chronos (full)</strong></td><td><strong>93.1</strong></td><td>94.4</td><td><strong>90.3</strong></td><td><strong>100.0</strong></td><td>85.7</td><td>87.5</td><td><strong>96.8</strong></td></tr><tr><td>No Initial Retrieval</td><td>76.7</td><td>83.3</td><td>64.5</td><td><strong>100.0</strong></td><td>71.4</td><td>81.2</td><td>74.2</td></tr><tr><td>No Dynamic Prompting</td><td>78.4</td><td>83.3</td><td>77.4</td><td><strong>100.0</strong></td><td>42.9</td><td><strong>93.8</strong></td><td>67.7</td></tr><tr><td>No Rerank</td><td>81.0</td><td>77.8</td><td>74.2</td><td><strong>100.0</strong></td><td>85.7</td><td>87.5</td><td>77.4</td></tr><tr><td>No Date Filter</td><td>78.4</td><td>88.9</td><td>71.0</td><td><strong>100.0</strong></td><td>57.1</td><td>68.8</td><td>80.6</td></tr><tr><td>Grep Only (no vector)</td><td>77.6</td><td><strong>100.0</strong></td><td>64.5</td><td>53.8</td><td><strong>100.0</strong></td><td>87.5</td><td>77.4</td></tr><tr><td>Vector Only (no grep)</td><td>80.2</td><td>94.4</td><td>80.6</td><td><strong>100.0</strong></td><td>85.7</td><td>62.5</td><td>71.0</td></tr><tr><td><strong>Turns Only (no events)</strong></td><td><strong>58.6</strong></td><td>55.6</td><td>51.6</td><td><strong>100.0</strong></td><td>42.9</td><td>43.8</td><td>61.3</td></tr></tbody></table><p><strong>Chronos High ablations:</strong></p><table tabindex="0"><thead><tr><th>Ablation</th><th>Overall</th><th>KU</th><th>MS</th><th>SSA</th><th>SSP</th><th>SSU</th><th>TR</th></tr></thead><tbody><tr><td><strong>Chronos (full)</strong></td><td><strong>94.8</strong></td><td><strong>100.0</strong></td><td><strong>90.3</strong></td><td><strong>100.0</strong></td><td><strong>100.0</strong></td><td><strong>93.8</strong></td><td>93.5</td></tr><tr><td>No Initial Retrieval</td><td>91.4</td><td><strong>100.0</strong></td><td>80.6</td><td><strong>100.0</strong></td><td>85.7</td><td><strong>93.8</strong></td><td>93.5</td></tr><tr><td>No Dynamic Prompting</td><td>94.8</td><td><strong>100.0</strong></td><td>87.1</td><td><strong>100.0</strong></td><td><strong>100.0</strong></td><td><strong>93.8</strong></td><td><strong>96.8</strong></td></tr><tr><td>No Rerank</td><td>92.2</td><td><strong>100.0</strong></td><td>87.1</td><td><strong>100.0</strong></td><td>85.7</td><td>87.5</td><td>93.5</td></tr><tr><td>No Date Filter</td><td>92.2</td><td>94.4</td><td>83.9</td><td><strong>100.0</strong></td><td>85.7</td><td><strong>93.8</strong></td><td><strong>96.8</strong></td></tr><tr><td>Grep Only (no vector)</td><td>87.1</td><td>94.4</td><td>83.9</td><td>61.5</td><td><strong>100.0</strong></td><td><strong>93.8</strong></td><td>90.3</td></tr><tr><td>Vector Only (no grep)</td><td>83.6</td><td><strong>100.0</strong></td><td>80.6</td><td><strong>100.0</strong></td><td>85.7</td><td>62.5</td><td>80.6</td></tr><tr><td><strong>Turns Only (no events)</strong></td><td>92.2</td><td>94.4</td><td>87.1</td><td><strong>100.0</strong></td><td>85.7</td><td>87.5</td><td><strong>96.8</strong></td></tr></tbody></table><p>Key findings:</p><ul><li>For Chronos Low: removing event access drops performance by <strong>34.5 points</strong> (93.1 → 58.6).</li><li>For Chronos High: removing event access only drops <strong>2.6 points</strong> (94.8 → 92.2) — more capable models partially compensate.</li><li>Dynamic prompting has no effect under Chronos High, reflecting advanced models&#39; ability to distinguish between query types without explicit guidance.</li><li>Both grep and vector search are necessary: removing either causes significant drops.</li></ul><hr><h2 id="_5-limitations" tabindex="-1">5. Limitations <a class="header-anchor" href="#_5-limitations" aria-label="Permalink to &quot;5. Limitations&quot;">​</a></h2><ol><li><strong>Dual indexing storage</strong>: Maintaining separate vector indexes for turns and events increases storage vs. turn-only systems. Mitigated by sparse event extraction focusing only on temporally-grounded state transitions.</li><li><strong>Offline extraction cost</strong>: LLM-powered event extraction adds indexing computation. Mitigated through batched processing (25 turns/batch, 5-turn overlap) with efficient small models.</li><li><strong>Inference complexity</strong>: Parallel retrieval over both calendars at query time. Mitigated through pre-retrieval of turn context before agent reasoning begins.</li></ol><hr><h2 id="_6-conclusion" tabindex="-1">6. Conclusion <a class="header-anchor" href="#_6-conclusion" aria-label="Permalink to &quot;6. Conclusion&quot;">​</a></h2><p>Chronos introduces a date-aware memory framework with dual calendars (event calendar + turn calendar), combined with turn-level dense retrieval, text search, and query-conditioned dynamic prompting. Multi-resolution temporal handling: preserves explicit dates exactly, calculates relative references from conversation timestamps, resolves ambiguous expressions to appropriate time ranges.</p><p>Results on LongMemEvalS (500 questions):</p><ul><li>Chronos Low (GPT-4o): 92.60% (+7.67% relative over prior SOTA)</li><li>Chronos High (Claude Opus 4.6): 95.60% (+3.02% relative over prior records)</li></ul><p>Particularly strong on multi-session aggregation (91.73%) and temporal reasoning (90.23%).</p><p>Key conclusion: Persistent conversational agents do not require comprehensive knowledge graph construction for high-fidelity long-horizon memory. Structuring fine-grained temporal events while preserving full dialogue context is sufficient for accurate update tracking, preference recall, and relative date reasoning.</p><p>Future directions: learning from accumulated event traces (weight updates), shared event histories for multi-agent or multi-user interactions.</p><hr><h2 id="appendix-a-full-model-comparison-on-longmemevals" tabindex="-1">Appendix A: Full Model Comparison on LongMemEvalS <a class="header-anchor" href="#appendix-a-full-model-comparison-on-longmemevals" aria-label="Permalink to &quot;Appendix A: Full Model Comparison on LongMemEvalS&quot;">​</a></h2><p><strong>Table 4: All 8 LLMs evaluated with Chronos (500 questions)</strong></p><table tabindex="0"><thead><tr><th>Model</th><th>Overall</th><th>KU (78)</th><th>MS (133)</th><th>SSA (56)</th><th>SSP (30)</th><th>SSU (70)</th><th>TR (133)</th></tr></thead><tbody><tr><td>Claude Opus 4.6</td><td><strong>95.60</strong></td><td><strong>100.00</strong></td><td>88.72</td><td><strong>100.00</strong></td><td><strong>100.00</strong></td><td>98.57</td><td>95.49</td></tr><tr><td>GPT-5-mini</td><td>94.20</td><td>96.15</td><td>85.71</td><td>98.21</td><td><strong>100.00</strong></td><td>97.14</td><td><strong>96.99</strong></td></tr><tr><td>Claude Sonnet 4.5</td><td>94.20</td><td>98.72</td><td><strong>89.47</strong></td><td><strong>100.00</strong></td><td>93.33</td><td><strong>98.57</strong></td><td>91.73</td></tr><tr><td>Claude Haiku 4.5</td><td>94.00</td><td>96.15</td><td>88.72</td><td><strong>100.00</strong></td><td>90.00</td><td>97.14</td><td>94.74</td></tr><tr><td>GPT-5.2</td><td>93.80</td><td>97.44</td><td>83.46</td><td><strong>100.00</strong></td><td><strong>100.00</strong></td><td><strong>98.57</strong></td><td>95.49</td></tr><tr><td>GPT-4o</td><td>92.60</td><td>96.15</td><td>91.73</td><td><strong>100.00</strong></td><td>80.00</td><td>94.29</td><td>90.23</td></tr><tr><td>Claude Code Sonnet</td><td>88.60</td><td>93.59</td><td>79.70</td><td>94.64</td><td>80.00</td><td>94.29</td><td>90.98</td></tr></tbody></table><hr><h2 id="key-references" tabindex="-1">Key References <a class="header-anchor" href="#key-references" aria-label="Permalink to &quot;Key References&quot;">​</a></h2><ul><li>Wu et al. (2025a) — <strong>LongMemEvalS benchmark</strong>: arXiv:2410.10813</li><li>Haley et al. (2025) — <strong>EmergenceMem</strong>: SOTA on LongMemEval with RAG (emergence.ai blog)</li><li>Barnes (2026) — <strong>Mastra Observational Memory</strong>: 95% on LongMemEval (mastra.ai/research)</li><li>McCormick &amp; Leer (2025) — <strong>Honcho benchmarking</strong>: plasticlabs.ai blog</li><li>Rasmussen et al. (2025) — <strong>Zep temporal knowledge graph</strong>: arXiv:2501.13956</li><li>Yao et al. (2023) — <strong>ReAct</strong>: arXiv:2210.03629</li><li>Ma et al. (2023) — <strong>Query rewriting for RAG</strong>: arXiv:2305.14283</li><li>Gao et al. (2022) — <strong>HyDE (Hypothetical Document Embeddings)</strong>: arXiv:2212.10496</li><li>Gao et al. (2024) — <strong>RAG survey</strong>: arXiv:2312.10997</li><li>Lumer &amp; Sen (2025) — <strong>Toolshed: RAG-tool fusion for agent tool selection</strong> (ICAART)</li><li>Asai et al. (2023) — <strong>Self-RAG</strong>: arXiv:2310.11511</li><li>Packer et al. (2024) — <strong>MemGPT</strong>: arXiv:2310.08560</li><li>Maharana et al. (2024) — <strong>LoCoMo benchmark</strong>: arXiv:2402.17753</li><li>Karpukhin et al. (2020) — <strong>DPR</strong>: arXiv:2004.04906</li><li>Robertson &amp; Zaragoza (2009) — <strong>BM25</strong>: Foundations and Trends in IR</li><li>Du et al. (2025) — <strong>MemR³</strong>: arXiv:2512.20237</li><li>Edge et al. (2025) — <strong>GraphRAG</strong>: arXiv:2404.16130</li><li>Wang et al. (2025) — <strong>Recursive summarization for dialogue</strong>: arXiv:2308.15022</li></ul>',101)])])}const m=e(a,[["render",s]]);export{u as __pageData,m as default};
